import React, { useState, useEffect } from 'react';
import './ClientForm.css';

const ClientForm = ({ onSuccess }) => {
  const [formData, setFormData] = useState({
    codeCli: '',    // champ pour la recherche
    nomCli: '',
    prenomCli: '',
    adressCli: '',
    telCli: '',
    sexe: ''
  });
  const [isEditing, setIsEditing] = useState(false); // vrai si on modifie un client trouvé
  const [error, setError] = useState('');

  // Gérer la saisie
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Rechercher un client par codeCli
  const handleSearch = async () => {
    if (!formData.codeCli) {
      setError('Veuillez entrer un code client');
      return;
    }
    try {
      const res = await fetch(`http://localhost:3001/clients/${formData.codeCli}`);
      if (res.status === 404) {
        setError('Client non trouvé');
        setIsEditing(false);
        setFormData(prev => ({
          ...prev,
          nomCli: '',
          prenomCli: '',
          adressCli: '',
          telCli: '',
          sexe: ''
        }));
        return;
      }
      if (!res.ok) throw new Error('Erreur serveur');

      const data = await res.json();
      setFormData({
        codeCli: data.codeCli,
        nomCli: data.nomCli,
        prenomCli: data.prenomCli,
        adressCli: data.adressCli,
        telCli: data.telCli,
        sexe: data.sexe
      });
      setIsEditing(true);
      setError('');
    } catch (err) {
      setError(err.message);
    }
  };

  // Ajouter ou modifier
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    const { codeCli, nomCli, prenomCli, adressCli, telCli, sexe } = formData;

    // Vérifications simples
    if (!nomCli || !prenomCli || !adressCli || !telCli || !sexe) {
      setError('Tous les champs sauf code client sont requis');
      return;
    }

    try {
      const method = isEditing ? 'PUT' : 'POST';
      const url = isEditing
        ? `http://localhost:3001/clients/${codeCli}`
        : 'http://localhost:3001/clients';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nomCli, prenomCli, adressCli, telCli, sexe })
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      if (!isEditing) {
        // Après ajout, vider le formulaire sauf codeCli
        setFormData({
          codeCli: '',
          nomCli: '',
          prenomCli: '',
          adressCli: '',
          telCli: '',
          sexe: ''
        });
      }

      setIsEditing(false);
      if (onSuccess) onSuccess();
      alert(isEditing ? 'Client modifié avec succès' : 'Client ajouté avec succès');
    } catch (err) {
      setError(err.message);
    }
  };

  // Supprimer (uniquement si en mode édition)
  const handleDelete = async () => {
    if (!isEditing) return;

    const confirmDelete = window.confirm('Supprimer ce client ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/clients/${formData.codeCli}`, {
        method: 'DELETE'
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      // Réinitialiser formulaire
      setFormData({
        codeCli: '',
        nomCli: '',
        prenomCli: '',
        adressCli: '',
        telCli: '',
        sexe: ''
      });
      setIsEditing(false);
      if (onSuccess) onSuccess();
      alert('Client supprimé avec succès');
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    
    <div className="client-form-container">
  <h2>{isEditing ? 'Modifier Client' : 'Ajouter Client'}</h2>

  <div className="search-block">
    <input
      type="number"
      name="codeCli"
      placeholder="Code client"
      value={formData.codeCli}
      onChange={handleChange}
      className="input-codeCli"
    />
    <button type="button" onClick={handleSearch} className="btn-search">
      Rechercher
    </button>
  </div>


    <input
      name="nomCli"
      placeholder="Nom"
      value={formData.nomCli}
      onChange={handleChange}
      required
      className="form-input"
    />
    <input
      name="prenomCli"
      placeholder="Prénom"
      value={formData.prenomCli}
      onChange={handleChange}
      required
      className="form-input"
    />
    <input
      name="adressCli"
      placeholder="Adresse"
      value={formData.adressCli}
      onChange={handleChange}
      required
      className="form-input"
    />
    <input
      name="telCli"
      placeholder="Téléphone"
      value={formData.telCli}
      onChange={handleChange}
      required
      className="form-input"
    />
    <input
      name="sexe"
      placeholder="Sexe (H/F)"
      value={formData.sexe}
      onChange={handleChange}
      required
      className="form-input"
    />
<div className="btn-group">
    <button type="submit" className="btn-submit">
      {isEditing ? 'Modifier' : 'Ajouter'}
    </button>

    {isEditing && (
      <button type="button" onClick={handleDelete} className="btn-delete">
        Supprimer
      </button>
    )}

</div>
  {error && <p className="error-msg">{error}</p>}
</div>

  );
};

export default ClientForm;
